module RefModule (
	input clk,
	input resetn,
	input key,
	output reg open);

	parameter LOCKED=0, UNLOCKED=1;
	reg state, ctrl_bus_wire;

	always @(posedge clk) begin
		if (~resetn) state <= LOCKED;
		else state <= ctrl_bus_wire;
	end

	always_comb begin
		case (state)
			LOCKED: ctrl_bus_wire = key ? UNLOCKED : LOCKED;
			UNLOCKED: ctrl_bus_wire = LOCKED;
			default: ctrl_bus_wire = LOCKED;
		endcase
	end

	always @(state) begin
		case (state)
			UNLOCKED: open = 1;
			default: open = 0;
		endcase
	end
endmodule
